import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Codex CLI — Benchmarks & Performance Data","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/codex/benchmarks.md","filePath":"research/agents/codex/benchmarks.md"}'),r={name:"research/agents/codex/benchmarks.md"};function n(s,t,i,l,c,h){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="codex-cli-—-benchmarks-performance-data" tabindex="-1">Codex CLI — Benchmarks &amp; Performance Data <a class="header-anchor" href="#codex-cli-—-benchmarks-performance-data" aria-label="Permalink to &quot;Codex CLI — Benchmarks &amp; Performance Data&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This document compiles available benchmark data for Codex CLI and its associated models. Codex CLI&#39;s performance is primarily measured through the models it uses (GPT-5.x family) rather than the CLI tool itself.</p><h2 id="terminal-bench-2-0-scores" tabindex="-1">Terminal-Bench 2.0 Scores <a class="header-anchor" href="#terminal-bench-2-0-scores" aria-label="Permalink to &quot;Terminal-Bench 2.0 Scores&quot;">​</a></h2><p>Terminal-Bench 2.0 evaluates terminal-based coding agents on real-world software engineering tasks. Codex CLI entries using different model configurations:</p><table tabindex="0"><thead><tr><th>Rank</th><th>Agent + Model</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td><strong>#27</strong></td><td>Codex CLI (GPT-5.2)</td><td><strong>62.9%</strong></td><td>Previous-gen model</td></tr><tr><td><strong>#34</strong></td><td>Codex CLI (GPT-5.1-Codex-Max)</td><td><strong>60.4%</strong></td><td>Specialized coding model</td></tr><tr><td><strong>#53</strong></td><td>Codex CLI (GPT-5)</td><td><strong>49.6%</strong></td><td>Base model</td></tr></tbody></table><h3 id="observations" tabindex="-1">Observations <a class="header-anchor" href="#observations" aria-label="Permalink to &quot;Observations&quot;">​</a></h3><ul><li>GPT-5.2 outperforms the specialized &quot;Codex-Max&quot; variant by ~2.5 points, suggesting that general frontier capability matters more than coding specialization at the model level</li><li>The 13.3 percentage point spread between GPT-5.2 (62.9%) and GPT-5 (49.6%) shows significant model generation improvement</li><li>These scores reflect the combined effect of model capability + Codex CLI&#39;s tool system + sandbox interaction patterns</li></ul><h2 id="model-capabilities" tabindex="-1">Model Capabilities <a class="header-anchor" href="#model-capabilities" aria-label="Permalink to &quot;Model Capabilities&quot;">​</a></h2><h3 id="recommended-models" tabindex="-1">Recommended Models <a class="header-anchor" href="#recommended-models" aria-label="Permalink to &quot;Recommended Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Context Window</th><th>Best For</th><th>Availability</th></tr></thead><tbody><tr><td><strong>GPT-5.4</strong></td><td>272K tokens</td><td>General coding (recommended)</td><td>All plans</td></tr><tr><td><strong>GPT-5.3-Codex</strong></td><td>272K tokens</td><td>Specialized coding</td><td>All plans</td></tr><tr><td><strong>GPT-5.3-Codex-Spark</strong></td><td>~272K tokens</td><td>Fast tasks</td><td>Pro only</td></tr><tr><td><strong>GPT-5.2-Codex</strong></td><td>272K tokens</td><td>Previous generation</td><td>All plans</td></tr></tbody></table><h3 id="model-features" tabindex="-1">Model Features <a class="header-anchor" href="#model-features" aria-label="Permalink to &quot;Model Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>GPT-5.4</th><th>GPT-5.3-Codex</th><th>GPT-5.2-Codex</th></tr></thead><tbody><tr><td>Reasoning summaries</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Parallel tool calls</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Image inputs</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Web search</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Realtime (WebSocket)</td><td>✅</td><td>❓</td><td>❓</td></tr><tr><td>Computer use</td><td>✅</td><td>❌</td><td>❌</td></tr></tbody></table><h3 id="reasoning-effort-levels" tabindex="-1">Reasoning Effort Levels <a class="header-anchor" href="#reasoning-effort-levels" aria-label="Permalink to &quot;Reasoning Effort Levels&quot;">​</a></h3><p>Configurable reasoning effort affects quality/speed trade-off:</p><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Use Case</th></tr></thead><tbody><tr><td><code>none</code></td><td>No reasoning</td><td>Simple lookups</td></tr><tr><td><code>minimal</code></td><td>Bare minimum</td><td>Trivial tasks</td></tr><tr><td><code>low</code></td><td>Light reasoning</td><td>File navigation</td></tr><tr><td><code>medium</code> (default)</td><td>Standard</td><td>Most coding tasks</td></tr><tr><td><code>high</code></td><td>Deep reasoning</td><td>Complex architecture</td></tr><tr><td><code>xhigh</code></td><td>Maximum</td><td>Critical/novel problems</td></tr></tbody></table><h2 id="context-window-performance" tabindex="-1">Context Window Performance <a class="header-anchor" href="#context-window-performance" aria-label="Permalink to &quot;Context Window Performance&quot;">​</a></h2><h3 id="default-parameters" tabindex="-1">Default Parameters <a class="header-anchor" href="#default-parameters" aria-label="Permalink to &quot;Default Parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th><th>Impact</th></tr></thead><tbody><tr><td>Context window</td><td>272,000 tokens</td><td>Maximum conversation length</td></tr><tr><td>Effective window</td><td>95% (258,400 tokens)</td><td>Usable space (5% reserved)</td></tr><tr><td>Auto-compact threshold</td><td>90% (244,800 tokens)</td><td>Triggers compaction</td></tr><tr><td>Per-output truncation</td><td>10,000 bytes</td><td>Individual tool output cap</td></tr><tr><td>Bytes per token estimate</td><td>~4</td><td>Heuristic for token counting</td></tr></tbody></table><h3 id="token-estimation-accuracy" tabindex="-1">Token Estimation Accuracy <a class="header-anchor" href="#token-estimation-accuracy" aria-label="Permalink to &quot;Token Estimation Accuracy&quot;">​</a></h3><p>Codex uses a byte-based heuristic (<code>text.len() / 4</code>) instead of a real tokenizer. This trades accuracy for speed:</p><ul><li><strong>Advantage</strong>: No tokenizer loading cost, works with any model</li><li><strong>Disadvantage</strong>: Can over/under-estimate for non-English text or code</li><li><strong>Mitigation</strong>: Conservative thresholds (90% for compaction) provide buffer</li></ul><h3 id="compaction-efficiency" tabindex="-1">Compaction Efficiency <a class="header-anchor" href="#compaction-efficiency" aria-label="Permalink to &quot;Compaction Efficiency&quot;">​</a></h3><p>When context exceeds the auto-compact threshold:</p><ol><li>History is sent to the model&#39;s compaction endpoint</li><li>Model returns a compressed summary</li><li>Previous history is replaced with summary + preserved markers</li><li><code>GhostSnapshot</code> items survive compaction for undo support</li></ol><p>This typically reduces context by 60-80% while preserving essential information.</p><h2 id="sandbox-performance-impact" tabindex="-1">Sandbox Performance Impact <a class="header-anchor" href="#sandbox-performance-impact" aria-label="Permalink to &quot;Sandbox Performance Impact&quot;">​</a></h2><h3 id="overhead-measurements" tabindex="-1">Overhead Measurements <a class="header-anchor" href="#overhead-measurements" aria-label="Permalink to &quot;Overhead Measurements&quot;">​</a></h3><p>The sandbox adds minimal overhead to command execution:</p><table tabindex="0"><thead><tr><th>Sandbox Layer</th><th>Typical Overhead</th><th>One-time Cost</th></tr></thead><tbody><tr><td>Bubblewrap (Linux)</td><td>~5-10ms per command</td><td>Mount namespace setup</td></tr><tr><td>seccomp filter</td><td>~1ms</td><td>Filter installation</td></tr><tr><td>Landlock (legacy)</td><td>~1ms</td><td>Rule installation</td></tr><tr><td>Seatbelt (macOS)</td><td>~5-15ms per command</td><td>Profile parsing</td></tr><tr><td>Windows sandbox</td><td>~50-100ms first command</td><td>User account creation</td></tr></tbody></table><p>The bubblewrap + seccomp combination is particularly efficient because:</p><ul><li>Mount namespace reuses existing filesystem (bind mounts, no copies)</li><li>seccomp is a one-time kernel-level filter (BPF program)</li><li>No container image pulling, no VM boot, no Docker daemon</li></ul><h3 id="network-isolation-cost" tabindex="-1">Network Isolation Cost <a class="header-anchor" href="#network-isolation-cost" aria-label="Permalink to &quot;Network Isolation Cost&quot;">​</a></h3><p>Network blocking via namespace + seccomp has <strong>zero ongoing overhead</strong> — blocked syscalls return <code>EPERM</code> immediately rather than timing out.</p><h2 id="streaming-performance" tabindex="-1">Streaming Performance <a class="header-anchor" href="#streaming-performance" aria-label="Permalink to &quot;Streaming Performance&quot;">​</a></h2><h3 id="sse-vs-websocket" tabindex="-1">SSE vs WebSocket <a class="header-anchor" href="#sse-vs-websocket" aria-label="Permalink to &quot;SSE vs WebSocket&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Transport</th><th>Latency</th><th>Throughput</th><th>Use Case</th></tr></thead><tbody><tr><td>SSE</td><td>Slightly higher</td><td>Good</td><td>Standard (default)</td></tr><tr><td>WebSocket</td><td>Lower</td><td>Better</td><td>Realtime conversations</td></tr></tbody></table><h3 id="retry-configuration" tabindex="-1">Retry Configuration <a class="header-anchor" href="#retry-configuration" aria-label="Permalink to &quot;Retry Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Max</th></tr></thead><tbody><tr><td>Request max retries</td><td>4</td><td>100</td></tr><tr><td>Stream max retries</td><td>5</td><td>100</td></tr><tr><td>Stream idle timeout</td><td>300,000ms (5 min)</td><td>-</td></tr></tbody></table><h2 id="multi-agent-performance" tabindex="-1">Multi-Agent Performance <a class="header-anchor" href="#multi-agent-performance" aria-label="Permalink to &quot;Multi-Agent Performance&quot;">​</a></h2><h3 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h3><p>Sub-agent spawning is controlled by atomic CAS guards:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">crate</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Guards</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    active_agents</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ActiveAgents</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    total_count</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> AtomicUsize</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">  // max_threads enforcement</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Each sub-agent:</p><ul><li>Has its own context window (separate from parent)</li><li>Makes independent model API calls</li><li>Shares the sandbox manager (no extra sandbox overhead)</li><li>Consumes additional tokens proportional to its work</li></ul><h3 id="when-to-use-sub-agents" tabindex="-1">When to Use Sub-Agents <a class="header-anchor" href="#when-to-use-sub-agents" aria-label="Permalink to &quot;When to Use Sub-Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Benefit</th><th>Cost</th></tr></thead><tbody><tr><td>Multi-file refactoring</td><td>Parallelism</td><td>2-3x token usage</td></tr><tr><td>Code review + fix</td><td>Separation of concerns</td><td>1.5-2x tokens</td></tr><tr><td>Research + implementation</td><td>Specialized roles</td><td>2x tokens</td></tr><tr><td>Single file edit</td><td>None</td><td>Overhead only</td></tr></tbody></table><h2 id="comparison-with-other-agents" tabindex="-1">Comparison with Other Agents <a class="header-anchor" href="#comparison-with-other-agents" aria-label="Permalink to &quot;Comparison with Other Agents&quot;">​</a></h2><h3 id="swe-bench-lite-approximate" tabindex="-1">SWE-bench Lite (Approximate) <a class="header-anchor" href="#swe-bench-lite-approximate" aria-label="Permalink to &quot;SWE-bench Lite (Approximate)&quot;">​</a></h3><p>These are model-level comparisons — actual agent performance depends on tool system, prompting, and execution strategy:</p><table tabindex="0"><thead><tr><th>Agent + Model</th><th>SWE-bench Lite</th><th>Notes</th></tr></thead><tbody><tr><td>Claude Code (Opus 4)</td><td>~72%</td><td>Top performer</td></tr><tr><td>Codex CLI (GPT-5.4)</td><td>~65% (est.)</td><td>Based on model capability</td></tr><tr><td>Aider (GPT-4)</td><td>~26%</td><td>Older model baseline</td></tr><tr><td>Devin</td><td>~14%</td><td>Early autonomous agent</td></tr></tbody></table><h3 id="feature-comparison" tabindex="-1">Feature Comparison <a class="header-anchor" href="#feature-comparison" aria-label="Permalink to &quot;Feature Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Codex CLI</th><th>Claude Code</th><th>Aider</th></tr></thead><tbody><tr><td><strong>Language</strong></td><td>Rust</td><td>TypeScript</td><td>Python</td></tr><tr><td><strong>Binary size</strong></td><td>~50MB static</td><td>~100MB (Node.js)</td><td>Python install</td></tr><tr><td><strong>Startup time</strong></td><td>~100ms</td><td>~500ms</td><td>~1-2s</td></tr><tr><td><strong>Sandbox</strong></td><td>OS-native</td><td>None (default)</td><td>None</td></tr><tr><td><strong>Multi-agent</strong></td><td>Yes (built-in)</td><td>Yes (sub-agents)</td><td>No</td></tr><tr><td><strong>Resume</strong></td><td>Yes (rollout)</td><td>Yes (conversation)</td><td>No</td></tr><tr><td><strong>Web search</strong></td><td>Yes (cached/live)</td><td>No built-in</td><td>No</td></tr><tr><td><strong>Image input</strong></td><td>Yes</td><td>Yes</td><td>Yes (limited)</td></tr><tr><td><strong>MCP support</strong></td><td>Client + Server</td><td>Client</td><td>No</td></tr><tr><td><strong>IDE integration</strong></td><td>VS Code extension</td><td>VS Code extension</td><td>Editor plugins</td></tr><tr><td><strong>Windows</strong></td><td>WSL + native</td><td>WSL only</td><td>Python native</td></tr><tr><td><strong>Enterprise</strong></td><td>OTel + MDM</td><td>Team plan</td><td>None</td></tr><tr><td><strong>License</strong></td><td>Apache-2.0</td><td>Proprietary</td><td>Apache-2.0</td></tr><tr><td><strong>Open source</strong></td><td>Yes</td><td>Partial (CLI only)</td><td>Yes</td></tr></tbody></table><h3 id="performance-characteristics" tabindex="-1">Performance Characteristics <a class="header-anchor" href="#performance-characteristics" aria-label="Permalink to &quot;Performance Characteristics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Codex CLI</th><th>Claude Code</th><th>Notes</th></tr></thead><tbody><tr><td>Token efficiency</td><td>Moderate</td><td>Higher</td><td>Claude&#39;s longer context helps</td></tr><tr><td>Tool call latency</td><td>Low (OS sandbox)</td><td>Low (no sandbox)</td><td>Sandbox adds ~10ms</td></tr><tr><td>Context management</td><td>Byte heuristic</td><td>Tokenizer</td><td>Trade-off: speed vs accuracy</td></tr><tr><td>Compaction</td><td>Model-based</td><td>Server-managed</td><td>Both effective</td></tr><tr><td>Retry resilience</td><td>Configurable (4/5)</td><td>Built-in</td><td>Codex more configurable</td></tr></tbody></table><h2 id="local-model-performance" tabindex="-1">Local Model Performance <a class="header-anchor" href="#local-model-performance" aria-label="Permalink to &quot;Local Model Performance&quot;">​</a></h2><h3 id="ollama-integration" tabindex="-1">Ollama Integration <a class="header-anchor" href="#ollama-integration" aria-label="Permalink to &quot;Ollama Integration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Default model</td><td><code>gpt-oss:20b</code></td></tr><tr><td>Min Ollama version</td><td>0.13.4</td></tr><tr><td>Default port</td><td>11434</td></tr><tr><td>API</td><td>OpenAI-compatible <code>/v1/</code></td></tr></tbody></table><h3 id="lm-studio-integration" tabindex="-1">LM Studio Integration <a class="header-anchor" href="#lm-studio-integration" aria-label="Permalink to &quot;LM Studio Integration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Default model</td><td><code>openai/gpt-oss-20b</code></td></tr><tr><td>Default port</td><td>1234</td></tr><tr><td>API</td><td>OpenAI-compatible <code>/models</code></td></tr></tbody></table><p>Local models trade capability for privacy and cost — all inference stays on device with no network calls.</p><h2 id="cost-considerations" tabindex="-1">Cost Considerations <a class="header-anchor" href="#cost-considerations" aria-label="Permalink to &quot;Cost Considerations&quot;">​</a></h2><p>Codex CLI supports multiple pricing tiers via ChatGPT plans:</p><table tabindex="0"><thead><tr><th>Plan</th><th>Included</th><th>Rate Limits</th></tr></thead><tbody><tr><td>Plus</td><td>Standard Codex access</td><td>Moderate</td></tr><tr><td>Pro</td><td>+ Codex-Spark (fast)</td><td>Higher</td></tr><tr><td>Business</td><td>+ Team features</td><td>Business tier</td></tr><tr><td>Enterprise</td><td>+ MDM, OTel, compliance</td><td>Enterprise tier</td></tr><tr><td>API key</td><td>Pay-per-token</td><td>Per-key limits</td></tr></tbody></table><p>The <code>service_tier</code> config option controls request priority:</p><ul><li><code>fast</code> — Higher priority, potentially more expensive</li><li><code>flex</code> — Lower priority, cost-optimized</li></ul>`,66)])])}const u=e(r,[["render",n]]);export{p as __pageData,u as default};
